#include <stdio.h>
#include <math.h>
int gcd(int a, int b) {
    if (b == 0)
        return a;
    return gcd(b, a % b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N, M;
        scanf("%lld %lld", &N, &M);
        long long sum = N * (N + 1) / 2;
        if (M == 0) {
            if (sum % 2 == 0) {
                printf("Yes\n");
            } else {
                printf("No\n");
            }
        } else if (sum < M) {
            printf("No\n");
        } else {
            long long diff = sum - M;
            if (gcd(diff, sum) == 1 || gcd(sum, sum - M) == 1) {
                printf("Yes\n");
            } else {
                printf("No\n");
            }
        }
    }
    return 0;
}

